arguments.new_str:
using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipFile now always sets the UTF-8 flag (EFS)
        // in entry headers. The legacy Java consumer expects Shift-JIS, so we
        // must specify the encoding explicitly to keep entries readable.
        var shiftJis = CodePagesEncodingProvider.Instance.GetEncoding("shift_jis")
                       ?? Encoding.UTF8;
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// .NET 9 breaking change: [FromKeyedServices("cache")] no longer falls
// back to a non-keyed registration; it throws InvalidOperationException.
// Register with the matching key so the controller can resolve it.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

